public class ModDataComponentTypes {
    public static final ComponentType<Integer> CUSTOM_ENERGY = ComponentType.<Integer>builder()
        .codec(Codec.INT)
        .packetCodec(PacketCodecs.INTEGER)
        .cache()
        .build();

    public static void register() {
        Registry.register(Registries.DATA_COMPONENT_TYPE, new Identifier("modid", "custom_energy"), CUSTOM_ENERGY);
    }
}

ItemStack stack = player.getMainHandStack();
Integer energy = stack.get(ModDataComponentTypes.CUSTOM_ENERGY);
if (energy != null) {
    player.sendMessage(Text.literal("能量: " + energy), false);
}

public record CustomData(int value, String name, boolean active) {
    public static final Codec<CustomData> CODEC = RecordCodecBuilder.create(instance ->
        instance.group(
            Codec.INT.fieldOf("value").forGetter(CustomData::value),
            Codec.STRING.fieldOf("name").forGetter(CustomData::name),
            Codec.BOOL.fieldOf("active").forGetter(CustomData::active)
        ).apply(instance, CustomData::new));
}

public static final ComponentType<CustomData> CUSTOM_DATA = ComponentType.<CustomData>builder()
    .codec(CustomData.CODEC)
    .packetCodec(CustomData.PACKET_CODEC)
    .cache()
    .build();

@Override
public void appendTooltip(ItemStack stack, TooltipContext context, List<Text> tooltip, TooltipType type) {
    super.appendTooltip(stack, context, tooltip, type);
    Integer energy = stack.get(ModDataComponentTypes.CUSTOM_ENERGY);
    if (energy != null) {
        tooltip.add(Text.literal("能量: " + energy).formatted(Formatting.GREEN));
    }
}
